### 阶段 1: 后端 API 完善 (4-6小时)

#### 1.1 实现迭代历史 API

在 `src/dashboard/routes/` 下创建或完善路由：

```typescript
// src/dashboard/routes/iterations.ts
import { FastifyInstance } from 'fastify';

export async function iterationRoutes(fastify: FastifyInstance) {

  // 获取迭代列表（分页）
  fastify.get('/api/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status, search } = request.query as any;

    // 从数据库查询
    const iterations = await fastify.iterationService.list({
      page,
      limit,
      status,
      search
    });

    return {
      data: iterations,
      total: iterations.length,
      page,
      limit
    };
  });

  // 获取迭代详情
  fastify.get('/api/iterations/:id', async (request, reply) => {
    const { id } = request.params as any;
    return await fastify.iterationService.getById(id);
  });

  // 获取迭代统计
  fastify.get('/api/iterations/stats/summary', async (request, reply) => {
    return await fastify.iterationService.getStats();
  });
}
```

