#### 2.3 实现核心逻辑

```javascript
// src/dashboard/public/scripts/iterations.js
/**
 * 迭代历史页面逻辑
 */

const CONFIG = {
  apiUrl: 'http://localhost:3000/api',
  pageSize: 20
};

const state = {
  iterations: [],
  currentPage: 1,
  totalPages: 1,
  filters: {
    status: '',
    search: ''
  }
};

// ==================== API 调用 ====================

/**
 * 获取迭代列表
 */
async function fetchIterations() {
  try {
    const params = new URLSearchParams({
      page: state.currentPage.toString(),
      limit: CONFIG.pageSize.toString(),
      ...(state.filters.status && { status: state.filters.status }),
      ...(state.filters.search && { search: state.filters.search })
    });

    const response = await fetch(`${CONFIG.apiUrl}/iterations?${params}`);
    const data = await response.json();

    state.iterations = data.data;
    state.totalPages = Math.ceil(data.total / CONFIG.pageSize);

    renderIterations();
    updatePagination();
  } catch (error) {
    console.error('获取迭代列表失败:', error);
    showError('获取迭代列表失败');
  }
}

/**
 * 获取迭代详情
 */
async function fetchIterationDetail(id) {
  try {
    const response = await fetch(`${CONFIG.apiUrl}/iterations/${id}`);
    return await response.json();
  } catch (error) {
    console.error('获取迭代详情失败:', error);
    return null;
  }
}

// ==================== 渲染函数 ====================

/**
 * 渲染迭代列表
 */
function renderIterations() {
  const tbody = document.getElementById('iterationsTableBody');
  tbody.innerHTML = '';

  if (state.iterations.length === 0) {
    tbody.innerHTML = '<tr><td colspan="6" style="text-align: center;">暂无数据</td></tr>';
    return;
  }

  state.iterations.forEach(iteration => {
    const tr = document.createElement('tr');

    tr.innerHTML = `
      <td>#${iteration.iterationNumber}</td>
      <td><div class="requirement-text">${escapeHtml(iteration.requirement || '-')}</div></td>
      <td><span class="status-badge ${iteration.status}">${getStatusText(iteration.status)}</span></td>
      <td>${formatDuration(iteration.duration)}</td>
      <td>${formatTime(iteration.createdAt)}</td>
      <td>
        <button class="btn-small" onclick="showDetail('${iteration.id}')">详情</button>
      </td>
    `;

    tbody.appendChild(tr);
  });
}

/**
 * 显示迭代详情
 */
async function showDetail(id) {
  const detail = await fetchIterationDetail(id);
  if (!detail) {
    showError('获取详情失败');
    return;
  }

  const modal = document.getElementById('detailModal');
  const content = document.getElementById('detailContent');

  content.innerHTML = `
    <div class="detail-section">
      <h3>基本信息</h3>
      <dl class="detail-list">
        <dt>迭代编号：</dt>
        <dd>#${detail.iterationNumber}</dd>
        <dt>状态：</dt>
        <dd><span class="status-badge ${detail.status}">${getStatusText(detail.status)}</span></dd>
        <dt>需求描述：</dt>
        <dd>${escapeHtml(detail.requirement || '-')}</dd>
        <dt>创建时间：</dt>
        <dd>${formatTime(detail.createdAt)}</dd>
        <dt>完成时间：</dt>
        <dd>${detail.completedAt ? formatTime(detail.completedAt) : '-'}</dd>
        <dt>耗时：</dt>
        <dd>${formatDuration(detail.duration)}</dd>
      </dl>
    </div>

    <div class="detail-section">
      <h3>Agent 执行结果</h3>
      <div class="agent-results">
        ${detail.agentResults?.map(agent => `
          <div class="agent-result">
            <div class="agent-name">${agent.agentName}</div>
            <div class="agent-status">
              <span class="status-badge ${agent.status}">${getStatusText(agent.status)}</span>
            </div>
            <div class="agent-output">${escapeHtml(agent.output || '-')}</div>
          </div>
        `).join('') || '<p>无执行结果</p>'}
      </div>
    </div>

    ${detail.gitCommit ? `
    <div class="detail-section">
      <h3>Git 提交信息</h3>
      <dl class="detail-list">
        <dt>Commit Hash：</dt>
        <dd><code>${detail.gitCommit.hash}</code></dd>
        <dt>分支：</dt>
        <dd>${detail.gitCommit.branch}</dd>
        <dt>提交消息：</dt>
        <dd>${escapeHtml(detail.gitCommit.message)}</dd>
      </dl>
    </div>
    ` : ''}
  `;

  modal.classList.add('active');
}

// ==================== 工具函数 ====================

function formatTime(date) {
  return new Date(date).toLocaleString('zh-CN');
}

function formatDuration(seconds) {
  if (!seconds) return '-';
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  return `${minutes}m ${seconds % 60}s`;
}

function getStatusText(status) {
  const statusMap = {
    'completed': '已完成',
    'failed': '失败',
    'running': '运行中',
    'pending': '待开始'
  };
  return statusMap[status] || status;
}

function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

function showError(message) {
  alert(message); // 可以改进为更好的提示方式
}

/**
 * 更新分页控件
 */
function updatePagination() {
  document.getElementById('pageInfo').textContent = 
    `第 ${state.currentPage} 页，共 ${state.totalPages} 页`;

  document.getElementById('prevPage').disabled = state.currentPage <= 1;
  document.getElementById('nextPage').disabled = state.currentPage >= state.totalPages;
}

// ==================== 事件监听 ====================

document.addEventListener('DOMContentLoaded', () => {
  // 初始加载
  fetchIterations();

  // 筛选事件
  document.getElementById('searchBtn').addEventListener('click', () => {
    state.filters.status = document.getElementById('statusFilter').value;
    state.filters.search = document.getElementById('searchInput').value;
    state.currentPage = 1;
    fetchIterations();
  });

  document.getElementById('resetBtn').addEventListener('click', () => {
    document.getElementById('statusFilter').value = '';
    document.getElementById('searchInput').value = '';
    state.filters = { status: '', search: '' };
    state.currentPage = 1;
    fetchIterations();
  });

  // 分页事件
  document.getElementById('prevPage').addEventListener('click', () => {
    if (state.currentPage > 1) {
      state.currentPage--;
      fetchIterations();
    }
  });

  document.getElementById('nextPage').addEventListener('click', () => {
    if (state.currentPage < state.totalPages) {
      state.currentPage++;
      fetchIterations();
    }
  });

  // 关闭弹窗
  document.getElementById('closeModal').addEventListener('click', () => {
    document.getElementById('detailModal').classList.remove('active');
  });

  // 点击背景关闭弹窗
  document.getElementById('detailModal').addEventListener('click', (e) => {
    if (e.target.id === 'detailModal') {
      document.getElementById('detailModal').classList.remove('active');
    }
  });
});
```

